import { createContext, type Context } from 'react';

export interface PresetItemContextProps {
  /** Indicates if the preset item is a recent timeframe */
  isRecent: boolean;
}

/** Context for the timeframe selector's preset items. Used to determine if the preset item is a recent timeframe without adding to the public api. */
export const PresetItemContext: Context<PresetItemContextProps> =
  createContext<PresetItemContextProps>({
    isRecent: false,
  });
